            player_name=d.get("player_name", ""),
            empire_score=d.get("empire_score", 0),
            resources=Resources.from_dict(d.get("resources", {})),
            territory=Territory.from_dict(d.get("territory", {})),
            buildings=[Building(**b) for b in d.get("buildings", [])],
