        log = cls()
        for event_dict in d.get("events", []):
            log.add_event(GameEvent.from_dict(event_dict))
        return log

    def __len__(self) -> int:
        return len(self._events)

    def __getitem__(self, index: int) -> GameEvent:
        return self._events[index]

